const Q_PHYSICS_2022_MODEL_IV=[{"id": "objective>Physics>2022 Model IV>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> When a metal is heated to a high temperature, electrons are emitted from its surface. This process is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">photoelectric emission </div>", "<div style=\"font-family:Cambria;font-size:17px;\">artificial radioactivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">field emission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thermionic emission</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Thermionic emission is the process by which free electrons are emitted from the surface of a metal when external heat energy is applied</div>", "topic": "ELEMENTARY MODERN PHYSICS : THERMIONIC EMISSIONS"}, {"id": "objective>Physics>2022 Model IV>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a semiconductor?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Germanium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Silicon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Copper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gallium Arsenide</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Copper is not a semiconductor. Semiconductors are materials that have properties of both conductors and insulators. Germanium, Silicon, and Gallium Arsenide are all semiconductors, while Copper is a good conductor of electricity.</div>", "topic": "INTRODUCTORY ELECTRONICS : METALS, SEMICONDUCTORS AND INSULATORS"}, {"id": "objective>Physics>2022 Model IV>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The internationally agreed system of units (SI) for physical measurements are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ib, ft, sec</div>", "<div style=\"font-family:Cambria;font-size:17px;\">g, m, sec</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kg, m, sec</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cm, g, sec</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The internationally agreed system of units (SI) for physical measurements are kilogram (kg) for mass, meter (m) for length, and second (sec) for time.</div>", "topic": "MEASUREMENTS AND UNITS : FUNDAMENTAL PHYSICAL QUANTITIES"}, {"id": "objective>Physics>2022 Model IV>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shortest length of the air column in a resonance tube closed at one end which resonates to a frequency of 720Hz is found to be 30cm. what is the wavelength of this sound in air? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">120cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60cm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At resonance l+c = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">λ</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">4</span> assuming c is negligible. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">l</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">λ<hr size=\"1\" />4</td></tr></table></div> <br/> λ = 4l <br/> λ = 4 × 30 <br/> λ = 120cm</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : RESONANCE"}, {"id": "objective>Physics>2022 Model IV>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a natural satellite?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Moon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sputnik 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rockets</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Examples of natural satellites are the Earth and Moon. The Earth rotates around the Sun and the Moon rotates around the Earth.</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2022 Model IV>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the energy required to eject a surface electron with a kinetic energy of 2.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-15</span>eV if the work function of the metal is 1.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-15</span>eV. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-15</span>eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-15</span>eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-15</span>eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-16</span>eV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The energy required to eject an electron is the sum of the work function and the kinetic energy of the electron. The work function is the minimum energy required to remove an electron from the surface of a metal. Therefore, the energy required is 1.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-15</span>eV (work function) + 2.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-15</span>eV (kinetic energy) = 3.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-15</span>eV.</div>", "topic": "ELEMENTARY MODERN PHYSICS : EINSTEIN’S EQUATION AND STOPPING POTENTIAL"}, {"id": "objective>Physics>2022 Model IV>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Steel is more suitable for permanent magnet than iron because the steel</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is easily demagnetized by shaking vigorously</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is an alloy of many metals </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is easily magnetized by alternating current through one cycle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">retains magnetism more than iron  </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Steel is more suitable for permanent magnet than iron because the steel retains magnetism more than iron  </div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2022 Model IV>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A p-n junction connected in a reversed bias arrangement is characterized by ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low resistance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high resistance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">medium resistance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high conductivity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A p-n junction connected in a reversed bias arrangement is characterized by high resistance and low conductivity.</div>", "topic": "INTRODUCTORY ELECTRONICS : DIODES"}, {"id": "objective>Physics>2022 Model IV>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A galvanometer of internal resistance 100Ω gives a full scale deflection for a current 10mA. Calculate the value of the resistance necessary to convert the galvanometer to a voltmeter reading up to 5V.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">400Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">800Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600Ω</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The current in the galvanometer is 10mA = 0.01A <br/> the internal resistance is 100Ω <br/> v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = voltage dropped at the internal resistance 100Ω <br/> v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 100 × 0.01 = 1V <br/> the total voltage measured  = 5V <br/> (5-1)V = 0.01 × R <br/> 4 = 0.01R <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4<hr size=\"1\" />0.01</td></tr></table></div> <br/> R = 400Ω</div>", "topic": "MAGNETIC FIELD : CONVERSION OF GALVANOMETERS TO AMMETERS AND VOLTMETER"}, {"id": "objective>Physics>2022 Model IV>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Why is power transmitted at high voltage instead of high current</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">to avoid power loss due to I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>R</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to speed up power transmission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to increase heat energy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">to increase energy loss</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When power is transmitted at high voltage it is called high tension transmission, to avoid power loss due to I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>R</div>", "topic": "ELECTRICAL ENERGY AND POWER : ELECTRIC POWER TRANSMISSION"}, {"id": "objective>Physics>2022 Model IV>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One litre is equivalent to how many cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1000cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10000cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">150cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One litre is equivalent to 1000 cubic centimeters (cm^3). This is a standard conversion in volume measurements.</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2022 Model IV>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The nucleus of an atom contains</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">protons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protons and neutrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protons and electrons</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The nucleus of an atom contains both protons and neutrons. Protons carry a positive charge, while neutrons carry no charge. Electrons, which carry a negative charge, are found in the electron cloud outside the nucleus.</div>", "topic": "ELEMENTARY MODERN PHYSICS : ELEMENTARY STRUCTURE OF THE ATOM"}, {"id": "objective>Physics>2022 Model IV>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The silvered surfaces in a thermos flask is to prevent heat loss by ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">radiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convection </div>", "<div style=\"font-family:Cambria;font-size:17px;\">conduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The silvered surfaces in a thermos flask prevent heat loss by radiation. Radiation is the transfer of heat through electromagnetic waves. The silvered surfaces reflect these waves back into the flask, reducing heat loss.</div>", "topic": "HEAT TRANSFER : THERMOS FLASK"}, {"id": "objective>Physics>2022 Model IV>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the cap of a gold leaf electroscope is positively and a negatively charged  body is brought near it, the divergence of the leaf</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains the same</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases and decreases later</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The divergence of the gold leaf decreases if it is brought near an opposite charge, and increases if brougth near similar charge.</div>", "topic": "ELECTROSTATICS : ELECTROSCOPE"}, {"id": "objective>Physics>2022 Model IV>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A glass rod rubbed with silk becomes positively charged because:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">some positive charges are transferred from the silk to the glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">some electrons are transferred from silk to the glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the silk becomes deficient in electrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">some electrons have been transferred from glass to silk</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A glass rod rubbed with silk becomes positively charged because some electrons have been transferred from the glass to the silk</div>", "topic": "ELECTROSTATICS"}, {"id": "objective>Physics>2022 Model IV>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following characteristics of sound waves depends on the frequency of the sound?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pitch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loudness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intensity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pitch of a sound is determined by its frequency. Higher frequencies result in higher pitched sounds, while lower frequencies result in lower pitched sounds. Loudness, quality, and intensity of sound are determined by other factors such as amplitude and waveform of the sound waves.</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : QUALITY, PITCH, INTENSITY AND LOUDNESS"}, {"id": "objective>Physics>2022 Model IV>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For total internal reflection to occur.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">light must be travelling from an optically more dense to an optically less dense medium.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the angle of incidence in the denser medium must be less than the critical angle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">light must be travelling from an optically less dense to an optically more dense medium.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the angle of incidence must be equal to the critical angle.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There are two conditions for total internal reflection to occur <br/> 1. light must be travelling from an optically more dense to an optically less dense medium. <br/> 2. the angle of incidence in the denser medium must be greater than the critical angle</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2022 Model IV>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The resistance of a 220V, 80 watt electric filament bulb is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">605Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">805Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">405Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">290Ω</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The resistance of a 220V, 80 watt electric filament bulb can be calculated using Ohm's law, which states that the resistance (R) is equal to the voltage (V) squared divided by the power (P). So, R = V^2 / P = 220^2 / 80 = 605Ω.</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2022 Model IV>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electric heater rated 240V,600A is used to heat a 3kg ice till it turned to water in 7 seconds. calculate the specific latent heat of fusion of the ice.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">336000Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">450Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">389000Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">65000Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H = mL <br/> H = IVt <br/> H = 600 × 240 × 7 = 1008000J <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">H<hr size=\"1\" />m</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1008000<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">336000Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div></div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF FUSION"}, {"id": "objective>Physics>2022 Model IV>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ball of mass of 400g, moving at a velocity of 30ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> is suddenly hit by a force of 10N for a time of 5secs. Find its new velocity.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">125ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">155ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">145ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">135ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mv-mu<hr size=\"1\" />t</td></tr></table></div> <br/> impulse Ft = m(v - u) <br/> 10 × 5 = 0.4( v - 30) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">30</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50<hr size=\"1\" />0.4</td></tr></table></div> <br/> v - 30 = 125 <br/> v = 125 + 30  <br/> v = 155ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2022 Model IV>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A vapour is said to be saturated when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">more molecules return to the liquid than leave it</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a dynamic equilibrium exists between the molecules of the liquid and the vapour molecules at a given temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the vapour pressure is atmospheric</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the temperature of the vapour varies</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> A vapour is said to be saturated when a dynamic equilibrium exists between the liquid molecules and the vapour molecules at a given temperature  </div>", "topic": "VAPOURS : UNSATURATED AND SATURATED VAPOURS"}, {"id": "objective>Physics>2022 Model IV>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The amount of heat needed to change the state of a substance is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">latent heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heat capacity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">specific heat capacity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">specific latent heat</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Latent heat is the heat supplied or removed which causes a change of state without a change in temperature.</div>", "topic": "CHANGE OF STATE : LATENT HEAT"}, {"id": "objective>Physics>2022 Model IV>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> The force with which an object is attracted to the earth is called its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">acceleration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gravity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">impulse</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gravity is the force that attracts a body towards the centre of the earth, or towards any other physical body having mass.</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2022 Model IV>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A capacitor of capacitance 12 μF is subjected to a potential difference of 800 volts across its terminal. Calculate the energy stored in the capacitor.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.86J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.86J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.84J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.6J</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The energy (E) stored in a capacitor can be calculated using the formula E = 1/2 * C * V^2, where C is the capacitance and V is the voltage. Substituting the given values, we get E = 1/2 * 12 * 10^-6 * (800)^2 = 3.84J.</div>", "topic": "CAPACITORS : ENERGY STORED IN A CAPACITOR"}, {"id": "objective>Physics>2022 Model IV>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following has the highest wavelength</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Red</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yellow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Orange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Violet</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the visible light spectrum, red light has the longest wavelength and violet has the shortest. Therefore, red has the highest wavelength.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>2022 Model IV>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electrochemical equivalent of silver is 0.0012gC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. If 72.0g of silver is to be deposited by electrolysis on a surface by passing a steady current for 7.5mins, the current must be?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">26.36A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">13.33A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">143.33A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">133.33A</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The amount of substance deposited during electrolysis is given by Faraday's first law of electrolysis which states that the mass (m) of a substance deposited at an electrode during electrolysis is directly proportional to the quantity of electricity (Q) that passes through the solution. Mathematically, m = ZQ, where Z is the electrochemical equivalent of the substance. From the question, Z = 0.0012gC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> and m = 72.0g. The time for the electrolysis is 7.5mins = 450s. Since Q = It, where I is the current and t is the time, we can substitute Q in the equation m = ZQ to get m = ZIt. Solving for I gives I = m/(Zt) = 72.0g / (0.0012gC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> * 450s) = 133.33A. Therefore, the current must be 133.33A.</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2022 Model IV>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following quantities has the same unit as impulse?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Change in momentum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">work done</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Impulse is the change in momentum of an object when a force is applied for an interval of time. It is calculated as the product of the force and the time interval during which the force is applied. Therefore, impulse has the same unit as change in momentum, which is kilogram meter per second (kg.m/s) in the SI system.</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2022 Model IV>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A uniform metre rule of weight 0.6N balances on a knife edge at the 55cm mark, find the mass hung at the 95cm mark.  <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">7.5kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.075kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.0075kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.45kg</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Taking the moment at P <br/> 40 × W = 0.6 × 5 <br/> 40W = 3 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">W</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />40</td></tr></table></div> <br/> W = 0.075N <br/> the mass = 0.0075kg</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>2022 Model IV>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At what temperature does water has its highest density</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water has its highest density at 4 degrees Celsius. This is due to the unique properties of water. As water cools from room temperature, it becomes more dense until it reaches 4 degrees Celsius. Below this temperature, water starts to form a crystalline structure as it freezes, which occupies more space and thus decreases its density.</div>", "topic": "THERMAL EXPANSION : LIQUIDS"}, {"id": "objective>Physics>2022 Model IV>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A density bottle holds 350g of liquid at 50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C and only 345g at 70<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C. Find the apparent cubic expansivity of the liquid.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">7.25 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.25 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.25 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.25 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ϒ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass expelled<hr size=\"1\" />mass remaining × temperature rise</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ϒ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">350-345<hr size=\"1\" />345(70-50)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ϒ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5<hr size=\"1\" />345(20)</td></tr></table></div> <br/> ϒ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span> = 7.25 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "THERMAL EXPANSION : LIQUIDS"}, {"id": "objective>Physics>2022 Model IV>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A relative density bottle weighs 40g when empty, 180g when filled with water and 250g when filled with a liquid. Find the relative density of the liquid.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.d</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">weight of liquid<hr size=\"1\" />weight of equal volume of water</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.d</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">250-40<hr size=\"1\" />180-40</td></tr></table></div> <br/> R.d = 1.5</div>", "topic": "LIQUIDS AT REST : RELATIVE DENSITY"}, {"id": "objective>Physics>2022 Model IV>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is/are true? <br/> I. Water has its highest density at 4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C <br/> II. Water has its least volume at 4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C <br/> III. Water contracts on cooling from any temperature until at 4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At 4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C: <br/> - Water has its highest density  <br/> - Water has its least volume  <br/> - Water contracts on cooling from any temperature until at 4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C <br/> </div>", "topic": "THERMAL EXPANSION : LIQUIDS"}, {"id": "objective>Physics>2022 Model IV>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following materials has its valence band overlaps with its conduction band.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conductor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">semiconductor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insulator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnet</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Conductors have their valence band overlapping with their conduction band <br/> Semicondutors have a band gap between the valence and conduction band but it is not as wide as that of the insulators <br/> Insulators have the largest band gaps.</div>", "topic": "INTRODUCTORY ELECTRONICS : METALS, SEMICONDUCTORS AND INSULATORS"}, {"id": "objective>Physics>2022 Model IV>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a property of x-rays</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they have very high frequency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they travel at the velocity of light (3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they have long wavelength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they are diffracted by crystals</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Properties of X-Rays <br/> - They have a shorter wavelength of the electromagnetic spectrum. <br/> - Requires high voltage to produce X-Rays. <br/> - They are used to capture the human skeleton defects. <br/> - They travel in a straight line and do not carry an electric charge with them. <br/> - They are capable of travelling in a vacuum.</div>", "topic": "ELEMENTARY MODERN PHYSICS : X-RAYS"}, {"id": "objective>Physics>2022 Model IV>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following phenomenon describes the wave nature of matter?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Electron diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Compton effect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Photoelectric effect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">radioactivity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electron diffraction is a phenomenon that demonstrates the wave nature of matter. It involves the interference and diffraction of waves associated with moving electrons, which can be explained using the principles of wave-particle duality in quantum mechanics. The Compton effect, photoelectric effect, and radioactivity are other quantum phenomena, but they do not specifically demonstrate the wave nature of matter.</div>", "topic": "ELEMENTARY MODERN PHYSICS : WAVE-PARTICLE PARADOX DUALITY OF MATTER"}, {"id": "objective>Physics>2022 Model IV>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On a certain day, the average air temperature was 35<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C and the dew point was 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C. If the s.v.p of water vapour was 18.4mmHg at 35<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C and 11.2mmHg at 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C, find the percentage relative humidity of the air.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">69%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60.9%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">51.8%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16%</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Relative</td><td style=\"text-align:center;\">humidity</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">s.v.p at dew point<hr size=\"1\" />s.v.p at room temperature</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100%</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.H</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">11.2<hr size=\"1\" />18.4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100%</td></tr></table></div> <br/> R.H = 0.609 × 100% <br/> R.H = 60.9%</div>", "topic": "VAPOURS : DEW POINT, HUMIDITY AND RELATIVE HUMIDITY"}, {"id": "objective>Physics>2022 Model IV>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the work function of a metal with a threshold frequency of 4.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">15</span>. <br/> [h = 6.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js, 1eV = 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">17.75eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.75eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.77eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">17.25eV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">W = hf<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> <br/> W = 6.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span> × 4.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">15</span> <br/> W = 2.84 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-18</span>J <br/> if 1eV = 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">W</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.84×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-18</span><hr size=\"1\" />1.6×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span></td></tr></table></div> <br/> W = 1.775 ×10eV <br/> W = 17.75eV</div>", "topic": "ELEMENTARY MODERN PHYSICS : EINSTEIN’S EQUATION AND STOPPING POTENTIAL"}, {"id": "objective>Physics>2022 Model IV>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A galvanometer of resistance 12Ω gives a full scale deflection when a current of 150mA flows through it. How will you convert it to an ammeter capable of measuring 5A?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.37Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.56Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.37Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.56Ω</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A shunt of RΩ will be connected in parralel to the galvanometer. <br/> current in the galvanometer = (5 - 0.15)A = 4.85A <br/> voltage across the shunt = 4.85 × R <br/> voltage across the galvanometer resistance = 0.15 × 12 = 1.8V <br/> since the connection is in parallel, the p.d across the shunt = p.d across the galvanometer resistance <br/> 4.85R = 1.8 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.8<hr size=\"1\" />4.85</td></tr></table></div> <br/> R = 0.37Ω</div>", "topic": "MAGNETIC FIELD : CONVERSION OF GALVANOMETERS TO AMMETERS AND VOLTMETER"}, {"id": "objective>Physics>2022 Model IV>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Why is earthing important in electrical appliances</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">To protect people from electrical shock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To maximize the power usage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To step down current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To prevent the switch damage</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Earthing is used to protect people from an electric shock. It does this by providing a path (a protective conductor) for a fault current to flow to earth. It also causes the protective device (either a circuit-breaker or fuse) to switch off the electric current to the circuit that has the fault.</div>", "topic": "ELECTROSTATICS"}, {"id": "objective>Physics>2022 Model IV>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is true about the boiling point of a liquid? <br/> I. increase in pressure at the surface of a liquid increases the boiling point. <br/> II. the presence of impurities raises the boiling point of a liquid <br/> III. wind has effect on the boiling point of a liquid</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Factors affecting the boiling point of a liquid <br/> - Increase in pressure at the surface of a liquid increases the boiling point. <br/> - The presence of impurities raises the boiling point of a liquid</div>", "topic": "CHANGE OF STATE : EVAPORATION AND BOILING"}];
